const sendError = (res, status, code, message) => {
  res.status(status).json({ error: { code, message } });
};

module.exports = { sendError };

const express = require('express');
const service = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', (req, res) => {
  const projects = service.getAllProjects();
  res.json({ projects });
});

router.post('/', (req, res) => {
  const { name } = req.body;
  if (!name) {
    return sendError(res, 400, 'BAD_REQUEST', 'Name is required');
  }
  const project = service.createProject(name);
  res.status(201).json({ project });
});

router.get('/:projectId', (req, res) => {
  const { projectId } = req.params;
  const project = service.getProjectById(projectId);
  if (!project) {
    return sendError(res, 404, 'NOT_FOUND', 'Project not found');
  }
  res.json({ project });
});

module.exports = router;

const { randomUUID } = require('node:crypto');

let projects = {};

const getAllProjects = () => {
  return Object.values(projects);
};

const createProject = (name) => {
  const projectId = randomUUID();
  const project = { id: projectId, name, members: [], tasks: [] };
  projects[projectId] = project;
  return project;
};

const getProjectById = (projectId) => {
  return projects[projectId];
};

module.exports = { getAllProjects, createProject, getProjectById };

const express = require('express');
const service = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', (req, res) => {
  const { projectId } = req.params;
  const { userId, role } = req.body;
  if (!userId || !role) {
    return sendError(res, 400, 'BAD_REQUEST', 'UserId and role are required');
  }
  const member = service.addMember(projectId, userId, role);
  if (!member) {
    return sendError(res, 409, 'CONFLICT', 'Duplicate member');
  }
  res.status(201).json({ member });
});

module.exports = router;

const { getProjectById } = require('../projects/service');
const { sendError } = require('../../lib/errors');

const addMember = (projectId, userId, role) => {
  const project = getProjectById(projectId);
  if (!project) {
    return null;
  }
  const existingMember = project.members.find(member => member.userId === userId);
  if (existingMember) {
    return null;
  }
  const member = { userId, role };
  project.members.push(member);
  return member;
};

module.exports = { addMember };

const express = require('express');
const service = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', (req, res) => {
  const { projectId } = req.params;
  const status = req.query.status;
  const tasks = service.getTasksByProjectId(projectId);
  if (!tasks) {
    return sendError(res, 404, 'NOT_FOUND', 'Project not found');
  }
  const filteredTasks = status ? tasks.filter(task => task.status === status) : tasks;
  res.json({ tasks: filteredTasks });
});

router.post('/', (req, res) => {
  const { projectId } = req.params;
  const task = service.createTask(projectId);
  if (!task) {
    return sendError(res, 404, 'NOT_FOUND', 'Project not found');
  }
  res.status(201).json({ task });
});

router.patch('/:taskId', (req, res) => {
  const { projectId, taskId } = req.params;
  const { status } = req.body;
  if (!status || !(status === 'todo' || status === 'done')) {
    return sendError(res, 400, 'BAD_REQUEST', 'Invalid status');
  }
  const task = service.updateTaskStatus(projectId, taskId, status);
  if (!task) {
    return sendError(res, 404, 'NOT_FOUND', 'Task not found');
  }
  res.json({ task });
});

module.exports = router;

const { getProjectById } = require('../projects/service');
const { randomUUID } = require('node:crypto');

const createTask = (projectId) => {
  const project = getProjectById(projectId);
  if (!project) {
    return null;
  }
  const taskId = randomUUID();
  const task = { id: taskId, status: 'todo' };
  project.tasks.push(task);
  return task;
};

const getTasksByProjectId = (projectId) => {
  const project = getProjectById(projectId);
  if (!project) {
    return null;
  }
  return project.tasks;
};

const updateTaskStatus = (projectId, taskId, status) => {
  const project = getProjectById(projectId);
  if (!project) {
    return null;
  }
  const task = project.tasks.find(task => task.id === taskId);
  if (!task) {
    return null;
  }
  task.status = status;
  return task;
};

module.exports = { createTask, getTasksByProjectId, updateTaskStatus };

const express = require('express');
const service = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', (req, res) => {
  const { projectId, taskId } = req.params;
  const { message } = req.body;
  if (!message) {
    return sendError(res, 400, 'BAD_REQUEST', 'Message is required');
  }
  const comment = service.addComment(projectId, taskId, message);
  if (!comment) {
    return sendError(res, 404, 'NOT_FOUND', 'Task not found');
  }
  res.status(201).json({ comment });
});

module.exports = router;

const { getProjectById } = require('../projects/service');
const { randomUUID } = require('node:crypto');

const addComment = (projectId, taskId, message) => {
  const project = getProjectById(projectId);
  if (!project) {
    return null;
  }
  const task = project.tasks.find(task => task.id === taskId);
  if (!task) {
    return null;
  }
  const commentId = randomUUID();
  const comment = { id: commentId, message };
  if (!task.comments) {
    task.comments = [];
  }
  task.comments.push(comment);
  return comment;
};

module.exports = { addComment };

const express = require('express');
const projectsRoutes = require('./modules/projects/routes');
const membersRoutes = require('./modules/members/routes');
tasksRoutes = require('./modules/tasks/routes');
commentsRoutes = require('./modules/comments/routes');

const app = express();
app.use(express.json());

app.get('/health', (req, res) => {
  res.status(200).json({ ok: true });
});

app.use('/projects', projectsRoutes);
app.use('/projects/:projectId/members', membersRoutes);
app.use('/projects/:projectId/tasks', tasksRoutes);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRoutes);

module.exports = app;

const { randomUUID } = require('node:crypto');
function generateId() {
  return randomUUID();
}
module.exports = { generateId };
